1905 /// It would be simpler to delete uses as they are processed, but we must avoid
1906 /// invalidating SCEV expressions.
1907 PHINode *WidenIV::createWideIV(SCEVExpander &Rewriter) {
1908   // Is this phi an induction variable?
1909   const SCEVAddRecExpr *AddRec = dyn_cast<SCEVAddRecExpr>(SE->getSCEV(OrigPhi));
1910   if (!AddRec)
1911     return nullptr;
1912 
1913   // Widen the induction variable expression.
1914   const SCEV *WideIVExpr = getExtendKind(OrigPhi) == ExtendKind::Sign
1915                                ? SE->getSignExtendExpr(AddRec, WideType)
1916                                : SE->getZeroExtendExpr(AddRec, WideType);
1917 
1918   assert(SE->getEffectiveSCEVType(WideIVExpr->getType()) == WideType &&
1919          "Expect the new IV expression to preserve its type");
1920 
1921   // Can the IV be extended outside the loop without overflow?
1922   AddRec = dyn_cast<SCEVAddRecExpr>(WideIVExpr);
